{
  "domain_analysis": {
    "business_context": "Order cancellation in a logistics/courier context. A user-initiated cancellation intersects multiple bounded contexts: order management, dispatch, billing, and last-mile delivery. The feasibility and cost of cancellation changes dramatically based on how far the order has progressed through the fulfillment pipeline.",
    "bounded_context": "Order Management (primary), with downstream effects on Dispatch, Billing, and Delivery",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A request by a user for a courier to pick up and deliver a shipment from origin to destination." },
      { "term": "Order Lifecycle", "definition": "The sequence of states an order passes through: PLACED → CONFIRMED → ASSIGNED → PICKED_UP → IN_TRANSIT → DELIVERED. Terminal states include DELIVERED, CANCELLED, and FAILED." },
      { "term": "Cancellation", "definition": "A user-initiated request to terminate an order before it reaches a terminal state. Not the same as a return or a refund, which are separate domain concepts." },
      { "term": "Cancellation Window", "definition": "The set of order states during which cancellation is permitted. Policy-driven, not a physical constraint." },
      { "term": "Cancellation Fee", "definition": "A charge applied when cancellation occurs after the platform has already committed operational resources (e.g., courier assigned or en route)." },
      { "term": "Requesting User", "definition": "The authenticated user who originally placed the order. Only this user (or an authorized agent acting on their behalf) may cancel it." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "An order can only be cancelled if it has NOT yet reached a terminal state (DELIVERED, CANCELLED, FAILED).",
      "invariant": true,
      "invariant_justification": "A delivered package is a physical fact — you cannot un-deliver it. Cancelling an already-cancelled order is a no-op that would corrupt state. This is a state-integrity constraint.",
      "testable_assertion": "Any cancellation request against an order in state DELIVERED, CANCELLED, or FAILED must be rejected with a clear error."
    },
    {
      "id": "BR-2",
      "rule": "Only the user who placed the order (the Requesting User) may cancel it.",
      "invariant": true,
      "invariant_justification": "Allowing arbitrary users to cancel other users' orders is a data-integrity and trust violation. Authorization is a hard constraint.",
      "testable_assertion": "A cancellation request where the authenticated user ID does not match the order's owner ID must be rejected with a 403/Forbidden."
    },
    {
      "id": "BR-3",
      "rule": "Cancellation of an order in state PLACED or CONFIRMED incurs no cancellation fee.",
      "invariant": false,
      "invariant_justification": "This is a business policy. A VP could decide to charge a processing fee even for early cancellations. Currently, no operational cost has been committed at this stage.",
      "testable_assertion": "When an order in state PLACED or CONFIRMED is cancelled, the cancellation fee is zero and a full refund is issued."
    },
    {
      "id": "BR-4",
      "rule": "Cancellation of an order in state ASSIGNED or PICKED_UP may incur a cancellation fee, as operational resources have been committed.",
      "invariant": false,
      "invariant_justification": "Fee amount and whether to charge at all is a business policy decision. The underlying principle — that committed resources have a cost — is real, but the threshold and amount are policy.",
      "testable_assertion": "When an order in state ASSIGNED or PICKED_UP is cancelled, the system applies the configured cancellation fee and the refund reflects the deduction."
    },
    {
      "id": "BR-5",
      "rule": "Cancellation of an order in state IN_TRANSIT must be rejected OR require special handling (e.g., reroute-to-return), as the package is physically in motion.",
      "invariant": true,
      "invariant_justification": "A package physically in a vehicle cannot simply vanish. The system must not pretend a cancellation is complete when the package still exists in the real world. This is a physical-reality constraint.",
      "testable_assertion": "A cancellation request for an IN_TRANSIT order is either rejected with a clear reason, or transitions to a special RETURN_REQUESTED state — never directly to CANCELLED."
    },
    {
      "id": "BR-6",
      "rule": "A cancelled order must emit a domain event (OrderCancelled) so that downstream contexts (billing, dispatch, notifications) can react.",
      "invariant": true,
      "invariant_justification": "Without the event, the courier remains assigned, the user is still charged, and the system is in an inconsistent state across bounded contexts. This is a data-consistency constraint.",
      "testable_assertion": "Upon successful cancellation, an OrderCancelled event is published containing order ID, cancellation reason, timestamp, and applicable fee."
    },
    {
      "id": "BR-7",
      "rule": "Every cancellation must record a reason (user-selected or free-text).",
      "invariant": false,
      "invariant_justification": "This is a business intelligence/analytics preference, not a state-integrity concern. The system functions correctly without it, but the business wants it for insight.",
      "testable_assertion": "The cancellation API requires a non-empty reason field; requests without one are rejected with a validation error."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An authenticated user has an order in state PLACED or CONFIRMED",
      "when": "The user requests cancellation of that order with a valid reason",
      "then": "The order transitions to CANCELLED, no fee is charged, a full refund is initiated, and an OrderCancelled event is emitted"
    },
    {
      "id": "AC-2",
      "given": "An authenticated user has an order in state ASSIGNED",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to CANCELLED, the applicable cancellation fee is applied, a partial refund is initiated, the assigned courier is notified and unassigned, and an OrderCancelled event is emitted"
    },
    {
      "id": "AC-3",
      "given": "An authenticated user has an order in state DELIVERED",
      "when": "The user requests cancellation of that order",
      "then": "The request is rejected with a clear message: 'Order has already been delivered and cannot be cancelled. Please initiate a return instead.'"
    },
    {
      "id": "AC-4",
      "given": "An authenticated user has an order in state CANCELLED",
      "when": "The user requests cancellation of that order again",
      "then": "The request is rejected idempotently — no state change, no duplicate events, no error — with a message confirming the order is already cancelled"
    },
    {
      "id": "AC-5",
      "given": "A user who did NOT place the order",
      "when": "That user requests cancellation of the order",
      "then": "The request is rejected with a 403 Forbidden and no state change occurs"
    },
    {
      "id": "AC-6",
      "given": "An authenticated user has an order in state IN_TRANSIT",
      "when": "The user requests cancellation",
      "then": "The request is either rejected with a message explaining the package is in transit, or the order transitions to RETURN_REQUESTED (not directly to CANCELLED)"
    },
    {
      "id": "AC-7",
      "given": "An order is in state ASSIGNED and the user requests cancellation",
      "when": "The cancellation succeeds",
      "then": "The courier receives a notification that the pickup is no longer required and is released back to the available pool"
    },
    {
      "id": "AC-8",
      "given": "An order is in state PICKED_UP (courier has the package but hasn't started transit)",
      "when": "The user requests cancellation",
      "then": "The order transitions to CANCELLED, a cancellation fee is applied, and the courier is instructed to return the package to the sender"
    },
    {
      "id": "AC-9",
      "given": "A cancellation request is submitted without a reason",
      "when": "The system validates the request",
      "then": "The request is rejected with a validation error requiring a cancellation reason"
    },
    {
      "id": "AC-10",
      "given": "A cancellation request is processed successfully",
      "when": "The OrderCancelled event is emitted",
      "then": "The event contains: orderId, userId, previousState, cancellationReason, cancellationFee, and timestamp"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Concurrent state change: user submits cancellation at the exact moment a courier marks the order as PICKED_UP",
      "expected_behavior": "Optimistic locking or version checks must prevent a lost update. The system must resolve to one consistent state — either the cancellation wins (courier is notified to return) or the pickup wins (user is informed cancellation is no longer possible at zero-fee). The order must never end up in an inconsistent state."
    },
    {
      "scenario": "User cancels an order and then the payment refund fails (e.g., card expired, payment provider down)",
      "expected_behavior": "The order still transitions to CANCELLED (the logistics operation stops), but the refund is queued for retry. The user is informed that the refund is being processed. Cancellation and refund are separate concerns — a refund failure must not block the operational cancellation."
    },
    {
      "scenario": "Bulk cancellation: user rapidly cancels multiple orders in quick succession",
      "expected_behavior": "Each cancellation is processed independently and idempotently. Rate limiting may apply but must not silently drop requests. Each order gets its own OrderCancelled event."
    },
    {
      "scenario": "Order is in CONFIRMED state but the system has already pre-authorized payment",
      "expected_behavior": "The pre-authorization must be voided (not refunded — void is cheaper and faster). The cancellation flow must distinguish between captured payments (refund) and pre-authorizations (void)."
    },
    {
      "scenario": "Network failure mid-cancellation: the order state is updated but the event is not published",
      "expected_behavior": "The system must use transactional outbox or equivalent pattern to guarantee the OrderCancelled event is eventually published. A cancelled order with no event leaves downstream systems (billing, dispatch) in an inconsistent state."
    },
    {
      "scenario": "User cancels an order that has a scheduled future pickup (e.g., pickup tomorrow at 9 AM)",
      "expected_behavior": "The scheduled pickup must be removed from the dispatch queue. If a courier was pre-assigned for the future slot, they must be notified and the slot freed."
    },
    {
      "scenario": "Cancelled order's tracking link is accessed by the recipient",
      "expected_behavior": "The tracking page must show a clear CANCELLED status. It must not show stale in-progress information or a generic 404."
    },
    {
      "scenario": "Partial fulfillment: a multi-package order where some packages are already delivered and others are not",
      "expected_behavior": "The spec says 'cancel their order' — it is ambiguous whether this means all-or-nothing or per-package. This must be clarified. If all-or-nothing, delivered packages cannot be un-delivered. If per-package, only undelivered packages should be cancellable."
    }
  ],

  "business_impact": {
    "financial": "Direct revenue impact: cancellation fees partially offset lost delivery revenue, but high cancellation rates signal pricing or service problems. Refund processing has a direct cost (payment processor fees are typically non-refundable). Late-stage cancellations waste courier time and fuel — a real operational cost that cancellation fees must at least partially recover.",
    "operational": "Cancellations after courier assignment create dead miles (courier traveled but no delivery completed). High cancellation rates in a zone can destabilize dispatch optimization. The cancellation flow must integrate cleanly with dispatch to free courier capacity immediately.",
    "user": "A smooth, transparent cancellation experience builds trust even when the user is unhappy. Hidden fees or unclear state messaging ('why can't I cancel?') drive negative reviews and churn. Users expect instant confirmation and clear refund timelines.",
    "risk": "Abuse risk: users could exploit free cancellation windows to hold courier capacity (place order, cancel last minute). Compliance risk: refund timelines may be subject to consumer protection regulations depending on jurisdiction. Data risk: cancellation reasons contain user sentiment data that may have privacy implications.",
    "stakeholders_affected": [
      { "group": "End Users (Senders)", "impact": "Primary actor — needs clear UX, transparent fees, and fast refunds. A poor cancellation experience is a top driver of churn." },
      { "group": "Recipients", "impact": "May be expecting a delivery that is now cancelled. Must be notified if they had tracking visibility." },
      { "group": "Couriers", "impact": "Directly affected when assigned orders are cancelled. Wasted time and fuel if already en route. Must be notified immediately to avoid unnecessary trips." },
      { "group": "Finance/Billing", "impact": "Must process refunds, void pre-authorizations, and reconcile cancellation fees. Needs clean event data." },
      { "group": "Customer Support", "impact": "Will handle disputes about cancellation fees and refund delays. Needs visibility into cancellation state and reason." },
      { "group": "Product/Analytics", "impact": "Cancellation reasons and rates are critical signals for product health. Needs structured reason data, not free-text noise." }
    ]
  },

  "confidence": {
    "level": 42,
    "reasoning": "The spec is a single sentence with no detail on cancellation window policy, fee structure, IN_TRANSIT handling, multi-package orders, or jurisdiction-specific refund rules. I have applied standard logistics domain knowledge to infer likely rules, but nearly every business rule I defined could be wrong for this specific business. The cancellation fee amounts, the IN_TRANSIT policy, and multi-package handling are all guesses that need PM confirmation.",
    "high_confidence_areas": [
      "Cannot cancel a delivered order (physical reality)",
      "Only the order owner can cancel (authorization invariant)",
      "OrderCancelled event must be emitted for downstream consistency",
      "Cancellation of already-cancelled order must be idempotent"
    ],
    "low_confidence_areas": [
      "Exact cancellation fee policy and amounts",
      "Whether IN_TRANSIT cancellation is blocked entirely or triggers a return flow",
      "Multi-package / partial fulfillment cancellation behavior",
      "Whether cancellation reason is mandatory or optional",
      "Refund timeline requirements and jurisdiction-specific rules",
      "Whether recipients should be notified of cancellations"
    ],
    "assumptions": [
      "The order lifecycle follows PLACED → CONFIRMED → ASSIGNED → PICKED_UP → IN_TRANSIT → DELIVERED (standard courier model)",
      "Cancellation fees exist and scale with fulfillment progress",
      "This is a user-initiated cancellation, not an admin or system cancellation (different rules would apply)",
      "The system supports domain events for cross-context communication",
      "Refunds are handled asynchronously and may fail independently of the cancellation itself"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order states are cancellable. The cancellation window policy is the single most important business decision for this feature and it is entirely unspecified.",
      "affected_stakeholders": ["End Users", "Couriers", "Finance"],
      "options": [
        "A) Allow cancellation up to CONFIRMED only (conservative — protects courier operations)",
        "B) Allow cancellation up to ASSIGNED with fee (balanced — common industry approach)",
        "C) Allow cancellation up to PICKED_UP with escalating fees (permissive — user-friendly but operationally expensive)"
      ],
      "recommendation": "Option B is the industry standard for courier platforms. Recommend confirming with PM."
    },
    {
      "type": "ambiguity",
      "description": "IN_TRANSIT cancellation behavior is undefined. Should it be blocked entirely, or should it trigger a return-to-sender flow? These are fundamentally different features with different complexity and cost.",
      "affected_stakeholders": ["End Users", "Couriers", "Product"],
      "options": [
        "A) Block cancellation once IN_TRANSIT — simpler, common approach",
        "B) Allow cancellation IN_TRANSIT by initiating a return — complex, requires reverse logistics"
      ],
      "recommendation": "Option A for MVP. Return-to-sender is a separate feature with its own domain complexity."
    },
    {
      "type": "ambiguity",
      "description": "Multi-package order cancellation is unspecified. If an order has 3 packages and 1 is already delivered, can the user cancel the remaining 2?",
      "affected_stakeholders": ["End Users", "Finance", "Customer Support"],
      "options": [
        "A) All-or-nothing: if any package is delivered, no cancellation",
        "B) Per-shipment: each package is independently cancellable"
      ],
      "recommendation": "Depends on whether 'order' and 'shipment' are separate aggregates. Need data model clarification."
    },
    {
      "type": "missing_context",
      "description": "Cancellation fee structure is not defined. Need: fee amounts or percentage, whether fees vary by order value, distance, or courier type.",
      "affected_stakeholders": ["End Users", "Finance", "Product"],
      "options": [
        "Flat fee per cancellation stage",
        "Percentage of order value",
        "Actual cost recovery (courier time + fuel)"
      ],
      "recommendation": "Flat fee per stage is simplest to implement and communicate to users. Need Finance input on amounts."
    },
    {
      "type": "missing_context",
      "description": "No mention of notification requirements. Should the recipient be notified? Should the courier get an SMS or push notification? What are the refund timeline commitments shown to the user?",
      "affected_stakeholders": ["Recipients", "Couriers", "Customer Support"],
      "options": [],
      "recommendation": "At minimum, courier must be notified immediately (operational necessity). Recipient notification is a product decision."
    }
  ],

  "rejection_reasons": []
}

